+/**
+ * Sanitize SVG content to prevent XSS attacks.
+ * Removes dangerous elements and attributes from SVG strings.
+ */
+
+/**
+ * List of SVG elements that could be used for XSS.
+ * @type {Array<string>}
+ */
+const DANGEROUS_ELEMENTS = [
+    'script',
+    'use',
+    'foreignObject',
+    'animate',
+    'set',
+    'animateMotion',
+    'animateTransform',
+    'animateColor'
+];
+
+/**
+ * List of attributes that could be used for XSS.
+ * @type {Array<string>}
+ */
+const DANGEROUS_ATTRIBUTES = [
+    'onload',
+    'onclick',
+    'onmouseover',
+    'onmouseout',
+    'onmousemove',
+    'onfocus',
+    'onblur',
+    'onerror',
+    'onabort',
+    'onactivate',
+    'onbegin',
+    'onend',
+    'onrepeat',
+    'onresize',
+    'onscroll',
+    'onunload',
+    'onzoom',
+    'href',
+    'xlink:href'
+];
+
+/**
+ * Recursively sanitize an SVG DOM element by removing dangerous
+ * elements and attributes.
+ * @param {Element} element - The element to sanitize.
+ */
+const sanitizeElement = function (element) {
+    // Remove dangerous child elements
+    const children = Array.from(element.childNodes);
+    for (const child of children) {
+        if (child.nodeType === child.ELEMENT_NODE) {
+            const tagName = child.tagName ? child.tagName.toLowerCase() : '';
+            if (DANGEROUS_ELEMENTS.indexOf(tagName) !== -1) {
+                element.removeChild(child);
+            } else {
+                // Remove dangerous attributes from this child
+                for (const attr of DANGEROUS_ATTRIBUTES) {
+                    if (child.hasAttribute(attr)) {
+                        child.removeAttribute(attr);
+                    }
+                }
+                // Check for javascript: URLs in href-like attributes
+                const hrefVal = child.getAttribute('href') || child.getAttribute('xlink:href') || '';
+                if (/^\s*javascript:/i.test(hrefVal)) {
+                    child.removeAttribute('href');
+                    child.removeAttribute('xlink:href');
+                }
+                sanitizeElement(child);
+            }
+        }
+    }
+};
+
+/**
+ * Sanitize an SVG string to remove XSS vectors.
+ * @param {string} svgString - The SVG string to sanitize.
+ * @returns {string} - The sanitized SVG string.
+ */
+const sanitize = function (svgString) {
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(svgString, 'image/svg+xml');
+    const svgElement = doc.documentElement;
+    sanitizeElement(svgElement);
+    const serializer = new XMLSerializer();
+    return serializer.serializeToString(svgElement);
+};
+
+module.exports = {sanitize};

